package update

import (
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"time"
)

const (
	cacheTTL      = 24 * time.Hour
	errorRetryTTL = 5 * time.Minute
	cacheFileName = "last-update-check.json"
)

// Cache manages the update check cache file
type Cache struct {
	filePath string
	data     *CacheData
}

// NewCache creates a new Cache instance
func NewCache() *Cache {
	return &Cache{
		data: &CacheData{},
	}
}

// Load reads cache from disk
func (c *Cache) Load() error {
	// Get cache file path
	if c.filePath == "" {
		path, err := c.getCacheFilePath()
		if err != nil {
			return fmt.Errorf("failed to determine cache path: %w", err)
		}
		c.filePath = path
	}

	// Read file
	data, err := os.ReadFile(c.filePath)
	if err != nil {
		return err // Return raw error for os.IsNotExist check
	}

	// Parse JSON
	if err := json.Unmarshal(data, c.data); err != nil {
		return fmt.Errorf("failed to parse cache: %w", err)
	}

	return nil
}

// Save writes cache to disk
func (c *Cache) Save() error {
	// Get cache file path
	if c.filePath == "" {
		path, err := c.getCacheFilePath()
		if err != nil {
			return fmt.Errorf("failed to determine cache path: %w", err)
		}
		c.filePath = path
	}

	// Ensure directory exists
	dir := filepath.Dir(c.filePath)
	if err := os.MkdirAll(dir, 0755); err != nil {
		return fmt.Errorf("failed to create cache directory: %w", err)
	}

	// Marshal to JSON
	data, err := json.MarshalIndent(c.data, "", "  ")
	if err != nil {
		return fmt.Errorf("failed to marshal cache: %w", err)
	}

	// Write to file
	if err := os.WriteFile(c.filePath, data, 0644); err != nil {
		return fmt.Errorf("failed to write cache: %w", err)
	}

	return nil
}

// IsExpired checks whether the cache should be refreshed.
// Successful checks use the long TTL; failed checks retry sooner to avoid dogpiling.
func (c *Cache) IsExpired() bool {
	if c.data.LastCheck.IsZero() {
		return true // No check recorded
	}
	ttl := cacheTTL
	if c.data.CheckError != "" {
		ttl = errorRetryTTL
	}
	return time.Since(c.data.LastCheck) > ttl
}

// getCacheFilePath returns the cache file path following XDG Base Directory spec
func (c *Cache) getCacheFilePath() (string, error) {
	// Check XDG_CACHE_HOME first
	cacheDir := os.Getenv("XDG_CACHE_HOME")
	if cacheDir == "" {
		// Fall back to ~/.cache
		homeDir, err := os.UserHomeDir()
		if err != nil {
			return "", fmt.Errorf("failed to get home directory: %w", err)
		}
		cacheDir = filepath.Join(homeDir, ".cache")
	}

	return filepath.Join(cacheDir, "ddx", cacheFileName), nil
}

package update

import (
	"context"
	"fmt"
	"os"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/config"
)

// Checker handles update checking logic
type Checker struct {
	currentVersion string
	config         *config.NewConfig
	cache          *Cache
	result         *UpdateCheckResult
}

// NewChecker creates a new Checker instance
func NewChecker(version string, cfg *config.NewConfig) *Checker {
	cache := NewCache()
	// Try to load cache, but don't fail if it doesn't exist
	_ = cache.Load()

	return &Checker{
		currentVersion: version,
		config:         cfg,
		cache:          cache,
	}
}

// ShouldCheck returns true if an update check is needed
func (c *Checker) ShouldCheck() bool {
	// Check if disabled in config
	if c.config.UpdateCheck != nil && !c.config.UpdateCheck.Enabled {
		return false
	}

	// Check if cache is expired or missing
	if c.cache.IsExpired() {
		return true
	}

	// Check if version changed (binary was upgraded)
	if c.cache.data.CurrentVersion != "" && c.cache.data.CurrentVersion != c.currentVersion {
		return true
	}

	// Cache is valid and fresh
	return false
}

// CheckForUpdate performs an update check if needed
// Returns the result, which is also stored in c.result for later retrieval
func (c *Checker) CheckForUpdate(ctx context.Context) (*UpdateCheckResult, error) {
	// Check if disabled via env var (takes precedence)
	if os.Getenv("DDX_DISABLE_UPDATE_CHECK") == "1" {
		c.result = &UpdateCheckResult{
			UpdateAvailable: false,
			LatestVersion:   c.currentVersion,
			Error:           nil,
		}
		return c.result, nil
	}

	// If check not needed, return cached result — but re-verify the cached
	// answer is still valid for the current binary version. If the user
	// upgraded past the cached LatestVersion, the cache is stale.
	if !c.ShouldCheck() {
		updateAvailable := c.cache.data.UpdateAvailable
		if updateAvailable && c.cache.data.LatestVersion != "" {
			needsUpgrade, err := NeedsUpgrade(c.currentVersion, c.cache.data.LatestVersion)
			if err != nil || !needsUpgrade {
				updateAvailable = false
			}
		}
		c.result = &UpdateCheckResult{
			UpdateAvailable: updateAvailable,
			LatestVersion:   c.cache.data.LatestVersion,
			Error:           nil,
		}
		return c.result, nil
	}

	// Perform actual check
	result := &UpdateCheckResult{}

	// Fetch latest release from GitHub
	release, err := FetchLatestRelease()
	if err != nil {
		result.Error = fmt.Errorf("failed to fetch latest release: %w", err)
		c.result = result

		// Update cache with error
		c.cache.data.LastCheck = time.Now()
		c.cache.data.CurrentVersion = c.currentVersion
		c.cache.data.CheckError = err.Error()
		_ = c.cache.Save() // Ignore save errors

		return result, err
	}

	// Compare versions
	needsUpgrade, err := NeedsUpgrade(c.currentVersion, release.TagName)
	if err != nil {
		result.Error = fmt.Errorf("failed to compare versions: %w", err)
		c.result = result

		// Update cache with error
		c.cache.data.LastCheck = time.Now()
		c.cache.data.CurrentVersion = c.currentVersion
		c.cache.data.CheckError = err.Error()
		_ = c.cache.Save() // Ignore save errors

		return result, err
	}

	// Update result
	result.UpdateAvailable = needsUpgrade
	result.LatestVersion = release.TagName
	c.result = result

	// Update cache with successful check
	c.cache.data.LastCheck = time.Now()
	c.cache.data.CurrentVersion = c.currentVersion
	c.cache.data.LatestVersion = release.TagName
	c.cache.data.UpdateAvailable = needsUpgrade
	c.cache.data.CheckError = ""

	_ = c.cache.Save() // Ignore save errors

	return result, nil
}

// IsUpdateAvailable returns the result from the last check
func (c *Checker) IsUpdateAvailable() (bool, string, error) {
	if c.result == nil {
		return false, "", nil
	}
	return c.result.UpdateAvailable, c.result.LatestVersion, c.result.Error
}
